import streamlit as st
from gtts import gTTS
import os

# --- 1. CONFIGURACIÓN ---
IMAGEN_BASE64 = "data:image/jpeg;base64,"
CREADOR = "David Lopez"

def hablar(texto):
    # Sin prefijo, fluidez total
    tts = gTTS(text=texto, lang='es')
    tts.save("saludo.mp3")
    st.session_state.hablando = True
    st.rerun()

st.set_page_config(page_title="Dex: Inteligencia Operativa", layout="centered")

# --- 2. ESTADO ---
if 'autenticado' not in st.session_state: st.session_state.autenticado = False
if 'hablando' not in st.session_state: st.session_state.hablando = False

# --- 3. LÓGICA DE RESPUESTA FLUIDA ---
def obtener_respuesta(prompt):
    p = prompt.lower()
    if "hola" in p: return "Hola, soy Dex. Fui creada por David Lopez. ¿En qué puedo ayudarte hoy?"
    if "cómo te llamas" in p: return "Mi nombre es Dex."
    if "quién te creó" in p: return f"Fui creada por {CREADOR}."
    if "mercado" in p: return "El mercado está bajo vigilancia. Tengo todos los protocolos de trading activos."
    return f"Entendido. Procesando tu solicitud sobre {prompt}."

# --- 4. INTERFAZ ---
st.markdown("<h1 style='text-align: center; color: #FFD700;'>Dex</h1>", unsafe_allow_html=True)

if not st.session_state.autenticado:
    codigo = st.text_input("Código de Acceso:", type="password")
    if st.button("Iniciar"):
        if codigo == "BELQUARIEL-17":
            st.session_state.autenticado = True
            st.rerun()
else:
    # Esfera dinámica (sin cambiar)
    color = "#00FF7F" if st.session_state.hablando else "#FFD700"
    st.markdown(f"""
    <div style="display: flex; justify-content: center; margin-top: 30px;">
        <img src="{IMAGEN_BASE64}" style="width: 350px; height: 350px; border-radius: 50%; object-fit: cover; border: 8px solid {color}; box-shadow: 0 0 50px {color}; transition: all 0.5s;">
    </div>
    """, unsafe_allow_html=True)

    # Reproducción invisible
    if st.session_state.hablando:
        # Se reproduce el audio sin que salga el bloque visual en la pantalla
        st.markdown(f'<audio src="saludo.mp3" autoplay="true"></audio>', unsafe_allow_html=True)
        st.session_state.hablando = False

    # Caja de texto (input limpio)
    prompt = st.chat_input("Dile algo a Dex...")
    if prompt:
        respuesta = obtener_respuesta(prompt)
        hablar(respuesta)

    if st.button("Cerrar"):
        st.session_state.autenticado = False
        st.rerun()
